// ── Error type (UDL `[Error] enum` mapping) ──────────────────────────────────
// Flat enum: no associated data on any variant; uniffi exposes the Display
// message as the Swift error description.
// The udl_derive(Error) attribute is applied by the scaffolding; no
// #[derive(uniffi::Error)] needed here.

#[derive(Debug, Error)]
pub enum ScError {
    #[error("archive error")]
    Archive,
    #[error("image error")]
    Image,
    #[error("storage error")]
    Storage,
    #[error("I/O error")]
    Io,
    #[error("unsupported format")]
    UnsupportedFormat,
    #[error("entry not found")]
    EntryNotFound,
}

impl From<anyhow::Error> for ScError {
    fn from(e: anyhow::Error) -> Self {
        let msg = e.to_string();
        if msg.contains("unsupported format") || msg.contains("unknown magic") {
            ScError::UnsupportedFormat
        } else if msg.contains("not found")
            || msg.contains("out of range")
            || msg.contains("no image")
        {
            ScError::EntryNotFound
        } else {
            ScError::Archive
        }
    }
}

