/// C-compatible session state; mirrors SessionStateRecord.
/// All fields use fixed-width types safe for C struct layouts.
#[repr(C)]
pub struct ScSessionState {
    pub page_index: u32,
    pub zoom_level: f64,
    pub rotation_degrees: i32,
    pub two_page_spread: bool,
    pub right_to_left: bool,
    pub scale_mode: i32,
    pub scroll_x: f64,
    pub scroll_y: f64,
}

/// C-callable: load persisted session state for `archive_path`.
///
/// On success writes state to `*out_state` and returns true.
/// On failure (no record, DB error) writes default state and returns false.
/// archive_path must be a valid NUL-terminated UTF-8 C string.
/// out_state must be a valid non-null pointer.
///
/// # Safety
/// `archive_path` must be a valid NUL-terminated UTF-8 C string.
/// `out_state` must be a valid non-null pointer to a `ScSessionState`.
#[no_mangle]
pub unsafe extern "C" fn sc_session_load(
    archive_path: *const std::ffi::c_char,
    out_state: *mut ScSessionState,
) -> bool {
    if archive_path.is_null() || out_state.is_null() {
        return false;
    }
    let path_str = match std::ffi::CStr::from_ptr(archive_path).to_str() {
        Ok(s) => s,
        Err(_) => return false,
    };
    // Only return true if the DB actually has a record for this path.
    let mgr = match open_session_db() {
        Ok(m) => m,
        Err(_) => return false,
    };
    if !mgr.exists(path_str) {
        return false;
    }
    let state = match mgr.load(path_str) {
        Ok(s) => s,
        Err(_) => return false,
    };
    let rec = state_to_record(state);
    *out_state = ScSessionState {
        page_index: rec.page_index,
        zoom_level: rec.zoom_level,
        rotation_degrees: rec.rotation_degrees,
        two_page_spread: rec.two_page_spread,
        right_to_left: rec.right_to_left,
        scale_mode: rec.scale_mode,
        scroll_x: rec.scroll_x,
        scroll_y: rec.scroll_y,
    };
    true
}

/// C-callable: persist session state for `archive_path`.
///
/// Returns true on success, false on DB error.
///
/// # Safety
/// Both pointers must be valid NUL-terminated UTF-8 C strings / structs.
#[no_mangle]
pub unsafe extern "C" fn sc_session_save(
    archive_path: *const std::ffi::c_char,
    state: *const ScSessionState,
) -> bool {
    if archive_path.is_null() || state.is_null() {
        return false;
    }
    let path_str = match std::ffi::CStr::from_ptr(archive_path).to_str() {
        Ok(s) => s,
        Err(_) => return false,
    };
    let s = &*state;
    let rec = SessionStateRecord {
        page_index: s.page_index,
        zoom_level: s.zoom_level,
        rotation_degrees: s.rotation_degrees,
        two_page_spread: s.two_page_spread,
        right_to_left: s.right_to_left,
        scale_mode: s.scale_mode,
        scroll_x: s.scroll_x,
        scroll_y: s.scroll_y,
    };
    session_save(path_str, rec).is_ok()
}

/// C-callable: delete persisted session state for `archive_path`.  No-op if not found.
///
/// # Safety
/// `archive_path` must be a valid NUL-terminated UTF-8 C string.
#[no_mangle]
pub unsafe extern "C" fn sc_session_delete_c(archive_path: *const std::ffi::c_char) {
    if archive_path.is_null() {
        return;
    }
    if let Ok(path_str) = std::ffi::CStr::from_ptr(archive_path).to_str() {
        session_delete(path_str);
    }
}

// ── Thumbnail C FFI ──────────────────────────────────────────────────────────

/// C-callable: generate a thumbnail from raw image bytes.
///
/// `image_bytes[0..image_len]` — compressed image data (JPEG, PNG, WebP, …).
/// `thumb_size`                 — max dimension (width and height) of the output.
///
/// On success: writes RGBA dimensions to `*out_width` / `*out_height`, writes
/// byte count to `*out_len`, sets `*error_code_out` to 0, and returns a
/// heap-allocated RGBA buffer (4 bytes per pixel, row-major).
/// Caller must release with `sc_free_bytes(ptr, *out_len)`.
/// On failure: returns NULL and sets `*error_code_out` to 1.
///
/// # Safety
/// `image_bytes` must point to `image_len` valid bytes.
/// `out_len`, `out_width`, `out_height` must be valid non-null pointers.
/// `error_code_out` may be null.
#[no_mangle]
pub unsafe extern "C" fn sc_thumbnail_from_bytes(
    image_bytes: *const u8,
    image_len: usize,
    thumb_size: u32,
    out_len: *mut usize,
    out_width: *mut u32,
    out_height: *mut u32,
    error_code_out: *mut i32,
) -> *mut u8 {
    let set_err = |code: i32| {
        if !error_code_out.is_null() {
            *error_code_out = code;
        }
    };
    if image_bytes.is_null() || out_len.is_null() || out_width.is_null() || out_height.is_null() {
        set_err(1);
        return std::ptr::null_mut();
    }
    let bytes = std::slice::from_raw_parts(image_bytes, image_len);
    let img = match image::load_from_memory(bytes) {
        Ok(i) => i,
        Err(_) => { set_err(1); return std::ptr::null_mut(); }
    };
    let spec = sc_image::ThumbnailSpec { width: thumb_size, height: thumb_size };
    let thumb = sc_image::thumbnail::generate_thumbnail(&img, spec).to_rgba8();
    *out_width = thumb.width();
    *out_height = thumb.height();
    let rgba: Vec<u8> = thumb.into_raw();
    let boxed: Box<[u8]> = rgba.into_boxed_slice();
    *out_len = boxed.len();
    set_err(0);
    Box::into_raw(boxed) as *mut u8
}

/// C-callable: cap image bytes to a maximum dimension using Rust Lanczos3 scaling.
///
/// If max(original_width, original_height) > `max_dim`, scales the image down
/// so the longest side equals `max_dim` (aspect-ratio preserved).
/// If the image already fits within `max_dim`, returns NULL and sets
/// `*error_code_out` to 0 — the caller should use the original bytes unchanged.
///
/// On scale: returns heap-allocated RGBA buffer; writes dimensions to
/// `*out_width`/`*out_height` and byte count to `*out_len`.
/// Caller releases with `sc_free_bytes(ptr, *out_len)`.
/// On failure: returns NULL and sets `*error_code_out` to 1.
/// No-scaling case: returns NULL and sets `*error_code_out` to 0.
///
/// # Safety
/// `image_bytes` must point to `image_len` valid bytes.
/// `out_len`, `out_width`, `out_height` must be valid non-null pointers.
/// `error_code_out` may be null.
#[no_mangle]
pub unsafe extern "C" fn sc_cap_image_bytes(
    image_bytes: *const u8,
    image_len: usize,
    max_dim: u32,
    out_len: *mut usize,
    out_width: *mut u32,
    out_height: *mut u32,
    error_code_out: *mut i32,
) -> *mut u8 {
    let set_err = |code: i32| {
        if !error_code_out.is_null() {
            *error_code_out = code;
        }
    };
    if image_bytes.is_null() || out_len.is_null() || out_width.is_null() || out_height.is_null() {
        set_err(1);
        return std::ptr::null_mut();
    }
    let bytes = std::slice::from_raw_parts(image_bytes, image_len);
    let img = match image::load_from_memory(bytes) {
        Ok(i) => i,
        Err(_) => { set_err(1); return std::ptr::null_mut(); }
    };
    let max_side = img.width().max(img.height());
    if max_side <= max_dim {
        // Already within bounds — no scaling needed.
        set_err(0);
        return std::ptr::null_mut();
    }
    let spec = sc_image::ThumbnailSpec { width: max_dim, height: max_dim };
    let scaled = sc_image::thumbnail::generate_thumbnail(&img, spec).to_rgba8();
    *out_width = scaled.width();
    *out_height = scaled.height();
    let boxed: Box<[u8]> = scaled.into_raw().into_boxed_slice();
    *out_len = boxed.len();
    set_err(0);
    Box::into_raw(boxed) as *mut u8
}

// ── Thumbnail functions ───────────────────────────────────────────────────────

/// Generate a thumbnail for raw image bytes. Returns raw RGBA bytes.
pub fn generate_thumbnail(image_bytes: &[u8], thumb_size: u32) -> Result<Vec<u8>, ScError> {
    let img = image::load_from_memory(image_bytes).map_err(|_| ScError::Image)?;
    let spec = sc_image::ThumbnailSpec {
        width: thumb_size,
        height: thumb_size,
    };
    let thumb = sc_image::thumbnail::generate_thumbnail(&img, spec);
    Ok(thumb.to_rgba8().into_raw())
}

/// Generate thumbnails for all pages in an archive in parallel.
pub fn generate_archive_thumbnails(
    archive_path: &str,
    thumb_size: u32,
) -> Result<Vec<ThumbnailRecord>, ScError> {
    let mut archive =
        sc_archive::open_archive(std::path::Path::new(archive_path)).map_err(ScError::from)?;

    let entries: Vec<(usize, Vec<u8>)> = archive
        .entries()
        .iter()
        .map(|e| e.index)
        .collect::<Vec<_>>()
        .into_iter()
        .filter_map(|idx| archive.read_entry(idx).ok().map(|b| (idx, b)))
        .collect();

    let spec = sc_image::ThumbnailSpec {
        width: thumb_size,
        height: thumb_size,
    };
    let thumbnails = sc_image::generate_thumbnails_sorted(&entries, spec);

    Ok(thumbnails
        .into_iter()
        .map(|(idx, img)| {
            let rgba = img.to_rgba8();
            ThumbnailRecord {
                index: idx as u32,
                rgba_bytes: rgba.clone().into_raw(),
                width: rgba.width(),
                height: rgba.height(),
            }
        })
        .collect())
}

// ── Type conversions ──────────────────────────────────────────────────────────

fn state_to_record(s: sc_storage::SessionState) -> SessionStateRecord {
    use sc_core::types::{PageOrder, Rotation, ScaleMode};
    SessionStateRecord {
        page_index: s.page_index as u32,
        zoom_level: s.zoom_level,
        rotation_degrees: match s.rotation {
            Rotation::R0 => 0,
            Rotation::R90 => 90,
            Rotation::R180 => 180,
            Rotation::R270 => 270,
        },
        two_page_spread: s.two_page_spread,
        right_to_left: matches!(s.page_order, PageOrder::RightToLeft),
        scale_mode: match s.scale_mode {
            ScaleMode::Original => 0,
            ScaleMode::FitWindow => 1,
            ScaleMode::FitWidth => 2,
        },
        scroll_x: s.scroll_x,
        scroll_y: s.scroll_y,
    }
}

fn record_to_state(r: SessionStateRecord) -> sc_storage::SessionState {
    use sc_core::types::{PageOrder, Rotation, ScaleMode};
    sc_storage::SessionState {
        page_index: r.page_index as usize,
        zoom_level: r.zoom_level,
        rotation: match r.rotation_degrees {
            90 => Rotation::R90,
            180 => Rotation::R180,
            270 => Rotation::R270,
            _ => Rotation::R0,
        },
        two_page_spread: r.two_page_spread,
        page_order: if r.right_to_left {
            PageOrder::RightToLeft
        } else {
            PageOrder::LeftToRight
        },
        scale_mode: match r.scale_mode {
            0 => ScaleMode::Original,
            2 => ScaleMode::FitWidth,
            _ => ScaleMode::FitWindow,
        },
        scroll_x: r.scroll_x,
        scroll_y: r.scroll_y,
    }
}

